import{_ as o,G as n,c as d,o as k,a6 as s,m as a,J as i,a as t,w as e}from"./chunks/framework.CS_FrCij.js";const H=JSON.parse('{"title":"3. Antibiotika","description":"Översikt av antibiotika-användning vid sårskador.","frontmatter":{"title":"3. Antibiotika","description":"Översikt av antibiotika-användning vid sårskador.","layout":"doc"},"headers":[],"relativePath":"sarvard/antibiotika.md","filePath":"sarvard/antibiotika.md","lastUpdated":1777710484000}'),c={name:"sarvard/antibiotika.md"},u=s('<h1 id="antibiotika" tabindex="-1">ANTIBIOTIKA <a class="header-anchor" href="#antibiotika" aria-label="Permalink to &quot;ANTIBIOTIKA&quot;">​</a></h1><h2 id="antibiotika-vid-sarskador" tabindex="-1">ANTIBIOTIKA VID SÅRSKADOR <a class="header-anchor" href="#antibiotika-vid-sarskador" aria-label="Permalink to &quot;ANTIBIOTIKA VID SÅRSKADOR&quot;">​</a></h2><p>Antibiotika har tidigare varit godtyckligt och har ofta getts i småkurer i profylaktiskt syfte. Denna praxis har i princip helt dött ut då studier visar ingen vinst samtidigt som det driver resistens. Av denna orsak måste individanpassning stå i centrum där sårmekanism, lokalisation, riskfaktorer, och grad av kontamination utgör viktiga beaktanden.</p><div class="warning custom-block"><p class="custom-block-title">PROFYLAKTISK ANTIBIOTIKA</p><p>METAANALYS:</p><p>1700 patienter inkluderades med exklusion av bitsår -&gt; AB vs INTE AB -&gt; Ingen signifikant skillnad vad gäller infektionsrisk!</p><p>Källa: Rosen&#39;s textbook of Medical Emergency.</p><p>En intressant reflektion är att det saknas RCT:er för AB-profylax</p></div><h3 id="riskfaktorer-och-overvaganden" tabindex="-1">Riskfaktorer och överväganden <a class="header-anchor" href="#riskfaktorer-och-overvaganden" aria-label="Permalink to &quot;Riskfaktorer och överväganden&quot;">​</a></h3><ul><li>Diabetes mellitus</li><li>Kronisk njursjukdom</li><li>Hög ålder</li><li>Steroider</li><li>Handskador</li><li>Djup punktion</li><li>Protesnära</li><li>Extremitet med dålig kärlförsörjning</li></ul><div class="info custom-block"><p class="custom-block-title">När det kan vara klokt att ge AB-profylax:</p><ul><li>Stor kontaminering (använd sunt förnuft!)</li><li>Omfattande krosskador -&gt; Mycket icke-viabel vävnad -&gt; hög infektionsrisk</li><li>Immunsuppresion</li></ul></div><h3 id="oppna-frakturer-ledskador-skottsar" tabindex="-1">Öppna frakturer, ledskador, skottsår <a class="header-anchor" href="#oppna-frakturer-ledskador-skottsar" aria-label="Permalink to &quot;Öppna frakturer, ledskador, skottsår&quot;">​</a></h3><p>I dessa fall SKA antibiotika ges då den potentiella infektionen betraktas som farlig med risk för permanenta skador på viktiga strukturer. Tillstånd vi är rädda för: septisk artrit, osteit, djupa mjukdelsinfektioner (fasciit, abscesser)</p><div class="warning custom-block"><p class="custom-block-title">PROSPEKTIV RCT</p><p>Visar minskad infektionsfrekvens. Tid till antibiotika var den viktigaste faktorn för gott utfall.</p><ul><li>Öppen fraktur utan mjukdelsskada (avulsion, krosskada, devitalisering) = AB i 24 h</li><li>Öppen komminut fraktur alt omfattande mjukdelsskada = AB i 72 h</li></ul></div><h3 id="bitsar" tabindex="-1">Bitsår <a class="header-anchor" href="#bitsar" aria-label="Permalink to &quot;Bitsår&quot;">​</a></h3><p>Vid dessa sårtyper behöver man sänka tröskeln för AB-användning. Särskilt kattbett. Typiska bakterier är strep-, stafylokocker, och pasteurella multocida.</p><p>Tidsaspekten och infektionsgraden är viktig för antibiotikaval. Pasteurella är en gramnegativ med mycket hög virulens och symptom utvecklar sig efter ca 4 h. Streptokocker har en liknande inkubationstid och koloniserar och invaderar snabbt. Stafylokocker är långsammare och bildar gärna abscesser. Vid mer långdragen debut ska agens utgå vara polymikrobiell varför bredspektrum AB är att föredra.</p><p>Ett viktigt beaktande är att flukloxacillin, perorala cefalosporiner, erytromycin, och klindamycin är inadekvata pga dålig effekt på Pasteurella.</p>',14),p={id:"katt",tabindex:"-1"},h=a("a",{class:"header-anchor",href:"#katt","aria-label":'Permalink to "<re>Katt</re>"'},"​",-1),f=a("ul",null,[a("li",null,"Djup punktion -> Svårt att rengöra adekvat. Överväg att sticka ner en uppdragningskanyl i såren och spola ordentligt. Bedöva innan."),a("li",null,"Upp till 40% blir infekterade"),a("li",null,"AB är särskilt viktigt vid handsår men gäller egentligen för alla kattbett")],-1),g={id:"hund",tabindex:"-1"},m=a("a",{class:"header-anchor",href:"#hund","aria-label":'Permalink to "<re>Hund</re>"'},"​",-1),b=a("ul",null,[a("li",null,"Upp till 16% blir infekterade"),a("li",null,"Betydligt större mängd stafylokocker än streptokocker jämfört med kattbett."),a("li",null,"Mer krossliknande skada -> enklare att rengöra"),a("li",null,"7/8 RCT visar ingen större profylaktisk AB-effekt.")],-1),_={id:"handbett",tabindex:"-1"},v=a("a",{class:"header-anchor",href:"#handbett","aria-label":'Permalink to "<re>Handbett</re>"'},"​",-1),A=a("ul",null,[a("li",null,'Vid MCP -> Antas vara människobett "fight bites" -> hög inf.risk'),a("li",null,"Patogener: Strep/staf, eikenella corrodens, bacteroides")],-1),x={class:"tip custom-block"},T=a("p",{class:"custom-block-title"},"ANTIBIOTIKAVAL FÖR ALLA BETTSÅR",-1),I=a("p",null,"Om < 24h ska strep/pasturella i första hand misstänkas och då ges:",-1),y=a("p",null,"Om > 72h (eller manifest infektion hos hundbett/människobett)",-1),B=a("p",null,"Om PC allergi",-1),P=a("p",null,"Om behov inneliggande vård pga omfattande infektion",-1),S=s('<h3 id="stickskada-fot" tabindex="-1">Stickskada fot <a class="header-anchor" href="#stickskada-fot" aria-label="Permalink to &quot;Stickskada fot&quot;">​</a></h3><ul><li>Upp till 15% infektionsrisk <ul><li>50% av dessa utvecklar cellulit</li><li>Septisk artrit</li><li>Abscess</li><li>Osteomyelit (Pseudomonas aerogonosa)</li></ul></li><li>Data visar INGEN fördel med AB-profylax</li><li>Vid högrisksår rekommenderas tidig uppföljning eller noggrann patientinstruktion när dom bör söka åter.</li><li>Strep/staf ska täckas in</li></ul>',2),q=a("h3",{id:"intraoral-laceration",tabindex:"-1"},[t("Intraoral laceration "),a("a",{class:"header-anchor",href:"#intraoral-laceration","aria-label":'Permalink to "Intraoral laceration"'},"​")],-1),V=a("ul",null,[a("li",null,"Bakterierik oral sekretion"),a("li",null,"Upp till 12% infektionsrisk. Om genomgående skada är risken 24%."),a("li",null,"AB bör ges vid genomgående skada.")],-1);function N(O,K,R,D,C,E){const r=n("re"),l=n("ye");return k(),d("div",null,[u,a("h4",p,[i(r,null,{default:e(()=>[t("Katt")]),_:1}),t(),h]),f,a("h4",g,[i(r,null,{default:e(()=>[t("Hund")]),_:1}),t(),m]),b,a("h4",_,[i(r,null,{default:e(()=>[t("Handbett")]),_:1}),t(),v]),A,a("div",x,[T,I,a("blockquote",null,[i(l,null,{default:e(()=>[t("Pencillin V 1 g x 3 i 7-10 dagar (barn: 25 mg/kg x 3)")]),_:1})]),y,a("blockquote",null,[i(l,null,{default:e(()=>[t("Amoxicillin/klavulansyra 500 mg x 3 (barn: 20 mg/kg x 3) i 7-10 dagar.")]),_:1})]),B,a("blockquote",null,[i(l,null,{default:e(()=>[t("Doxycyklin 100 mg x 2 i 1 dag, därefter 100mg x 1 i 8 dagar alt trim/sulfa 800/160 mg x 2 i 10d.")]),_:1})]),P,a("blockquote",null,[i(l,null,{default:e(()=>[t("Bensylpenicillin 3 g x 3 iv (barn 50 mg/kg)")]),_:1})]),a("blockquote",null,[i(l,null,{default:e(()=>[t("Cefotaxim 1 g x 3 iv")]),_:1})])]),S,a("blockquote",null,[i(l,null,{default:e(()=>[t("Flukloxacillin 1 g x 3 i 7-10 dagar")]),_:1})]),q,V,a("blockquote",null,[i(l,null,{default:e(()=>[t("Penicillin V 500 mg x 2 i 5 dagar")]),_:1})])])}const L=o(c,[["render",N]]);export{H as __pageData,L as default};
